mapper.update:
UPDATE news
SET view_count = view_count + 1
WHERE news_id = #{news_id}

mapper.select:

        SELECT * FROM (
	        SELECT ROWNUM AS rn, inner_query.*
	        FROM (
	            SELECT *
	            FROM news
	            ORDER BY published_date DESC
	        ) inner_query
	        WHERE ROWNUM <= #{offset} + #{amount}
	    )
	    WHERE rn > #{offset}
